+		curGiven = person.Names[0].GivenName
+		curFamily = person.Names[0].FamilyName
+	}
+	if givenSet {
+		curGiven = strings.TrimSpace(given)
+	}
+	if familySet {
+		curFamily = strings.TrimSpace(family)
+	}
+	person.Names = []*people.Name{{GivenName: curGiven, FamilyName: curFamily}}
